#import "ChatItemModel.h"

@implementation ChatItemModel

+ (instancetype)fromDict:(NSDictionary *)dict {
    ChatItemModel *m = [[ChatItemModel alloc] init];
    m.chatId = [dict[@"chatId"] isKindOfClass:[NSString class]] ? dict[@"chatId"] : @"";
    m.title = [dict[@"title"] isKindOfClass:[NSString class]] ? dict[@"title"] : @"";
    m.subtitle = [dict[@"subtitle"] isKindOfClass:[NSString class]] ? dict[@"subtitle"] : @"";
    m.time = [dict[@"time"] isKindOfClass:[NSString class]] ? dict[@"time"] : @"";
    if ([dict[@"icon"] isKindOfClass:[NSString class]]) {
        m.icon = dict[@"icon"];
    }
    if ([dict[@"avatarPath"] isKindOfClass:[NSString class]]) {
        m.avatarPath = dict[@"avatarPath"];
    }
    return m;
}

- (NSDictionary *)toDict {
    NSMutableDictionary *d = [@{ @"chatId": self.chatId ?: @"",
                                  @"title": self.title ?: @"",
                                  @"subtitle": self.subtitle ?: @"",
                                  @"time": self.time ?: @"" } mutableCopy];
    if (self.icon) { d[@"icon"] = self.icon; }
    if (self.avatarPath) { d[@"avatarPath"] = self.avatarPath; }
    return d;
}

