            for (NSString *t in texts) {
                [msgs addObject:[[MessageModel alloc] initWithText:t time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([title isEqualToString:@"Learn"]) {
            NSArray *texts = @[ @"What do you want to learn? I can help you develop a reasonable study plan to double your learning efficiency",
                                @"Do you like reading books?"];
            for (NSString *t in texts) {
                [msgs addObject:[[MessageModel alloc] initWithText:t time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO]];
            }
        }
    }
    // 非示例项或未命中标题时，退化为两条问候语；优先使用该聊天项的标题作为名称
    if (msgs.count == 0) {
