@property (nonatomic, strong) NSTimer *speechDebounceTimer;
@property (nonatomic, assign) NSTimeInterval speechDebounceInterval;
@property (nonatomic, assign) NSInteger speakingMessageRow;
@property (nonatomic, assign) NSInteger lastSpokenIndex;

@property (nonatomic, strong) ShowHeaderView *headerView;

@end

@implementation ChatViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    if (self.title.length == 0) {
        self.title = @"Chat";
    }
    NSDictionary *titleAttributes = @{
        NSFontAttributeName: [UIFont boldSystemFontOfSize:ZOOM(18)],
        NSForegroundColorAttributeName: [UIColor blackColor]
    };
    [self.navigationController.navigationBar setTitleTextAttributes:titleAttributes];
    self.navigationItem.leftBarButtonItem = self.backBarItem;
    self.navigationItem.rightBarButtonItems = @[self.voiceBarItem, self.cleanBarItem];
    [self setupUI];
    [_headerView showAppearAnimation];
    // 列表配置
    self.tableView.delegate = self;
    self.tableView.dataSource = self;
    self.tableView.separatorStyle = UITableViewCellSeparatorStyleNone;
    [self.tableView registerClass:[ChatMessageCell class] forCellReuseIdentifier:@"ChatMessageCell"];

    // 加载当前会话的消息；若为空则按会话类型恢复默认预设
    if (self.chatId.length == 0) {
        self.chatId = @"default";
    }
    self.messages = [[ChatStorage loadMessagesForChatId:self.chatId] mutableCopy];
    if (self.messages.count == 0) {
        [ChatStorage resetMessagesToPresetForChatId:self.chatId];
        self.messages = [[ChatStorage loadMessagesForChatId:self.chatId] mutableCopy];
    }
    [self.tableView reloadData];

    // 点击空白收起键盘
    UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleTapOutside)];
    tap.cancelsTouchesInView = NO;
    tap.delegate = self;
    [self.view addGestureRecognizer:tap];

    // 键盘通知
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillChange:) name:UIKeyboardWillChangeFrameNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];

    // 预热网络，尽早触发系统网络权限弹窗或建立连接，避免首条真实消息被打断
    [[AiServerManager sharedManager] warmUpNetwork:^(BOOL online) {
        if (!online) {
            NSString *msg = @"Network is unavailable or mobile data is restricted. You can enable network permissions for the app in Settings later.";
            UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Network Unavailable" message:msg preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *settings = [UIAlertAction actionWithTitle:@"Open Settings" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
                NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
                if ([[UIApplication sharedApplication] canOpenURL:url]) {
                    [[UIApplication sharedApplication] openURL:url options:@{} completionHandler:nil];
                }
            }];
            UIAlertAction *ok = [UIAlertAction actionWithTitle:@"OK" style:UIAlertActionStyleCancel handler:nil];
            [alert addAction:settings];
            [alert addAction:ok];
            [self presentViewController:alert animated:YES completion:nil];
        }
    }];
}


#pragma mark - setup UI

- (void)setupUI {
    self.view.backgroundColor = BACKGROUND_COLOR;
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.headerView];
    [self.view addSubview:self.tableView];
    [self.view addSubview:self.chatBar];
    [self.chatBar addSubview:self.textfield];
    [self.chatBar addSubview:self.sendButton];
}

- (void)addAllConstraints {
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view).offset(ZOOM(-724));
    }];

    [_tableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom).offset(ZOOMW(16));
        make.left.right.equalTo(self.view);
        make.bottom.equalTo(self.chatBar.mas_top);
    }];

    [_chatBar mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.view);
        self.inputViewBottomConstraint = make.bottom.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(98));
    }];

    [_sendButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.chatBar).offset(ZOOM(16));
        make.right.equalTo(self.chatBar).offset(ZOOM(-16));
        make.width.mas_equalTo(ZOOM(52));
        make.height.mas_equalTo(ZOOM(44));
    }];

    [_textfield mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.chatBar).offset(ZOOM(16));
        make.left.equalTo(self.chatBar).offset(ZOOM(16));
        make.right.equalTo(self.sendButton.mas_left).offset(ZOOM(-16));
        make.height.mas_equalTo(ZOOM(44));
    }];
}


#pragma mark - events

- (void)backToChatList {
    [self.navigationController popViewControllerAnimated:YES];
}

- (void)turnVoice {
    self.voiceEnabled = !self.voiceEnabled;
    [self updateVoiceBarItemAppearance];
    if (!self.voiceEnabled) {
        if (self.speechSynthesizer.isSpeaking) {
            [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
        }
        return;
    }
    // 重新打开语音：若存在当前AI消息，按闭合句续播并补播尾段
    if (self.messages.count > 0) {
        self.speakingMessageRow = self.messages.count - 1;
        MessageModel *last = [self.messages lastObject];
        if (last.type == MessageTypeReceived) {
            [self enqueueClosedSentencesForLatestAI];
            NSString *text = last.text ?: @"";
            if (text.length > self.lastSpokenIndex) {
                NSString *tail = [text substringFromIndex:self.lastSpokenIndex];
                NSString *lang = [self isChineseText:tail] ? @"zh-CN" : @"en-US";
                [self enqueueSpeakText:tail language:lang];
                self.lastSpokenIndex = text.length;
            }
        }
    }
}

- (void)handleClean {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Delete" message:@"All chat history will be cleared after deletion." preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *cancel = [UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil];
    __weak typeof(self) weakSelf = self;
    UIAlertAction *confirm = [UIAlertAction actionWithTitle:@"Confirm" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        [ChatStorage resetMessagesToPresetForChatId:self.chatId];
        self.messages = [[ChatStorage loadMessagesForChatId:self.chatId] mutableCopy];
        [self.tableView reloadData];
        [self scrollToBottom];
    }];
    [alert addAction:cancel];
    [alert addAction:confirm];
    [self presentViewController:alert animated:YES completion:nil];
}

#pragma mark - input & send

- (void)textfieldEditingChanged:(UITextField *)textField {
    NSString *trimmed = [textField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    BOOL hasText = trimmed.length > 0;
    self.sendButton.enabled = hasText;
    self.sendButton.backgroundColor = hasText ? RGBA(135, 127, 233, 1) : RGB(203, 203, 203);
}

- (void)handleSend {
    NSString *trimmed = [self.textfield.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (trimmed.length == 0) {
        return;
    }
    // 停止当前朗读与节流
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }
    if (self.speechDebounceTimer) {
        [self.speechDebounceTimer invalidate];
        self.speechDebounceTimer = nil;
    }
    // 追加用户消息
    MessageModel *userMsg = [[MessageModel alloc] initWithText:trimmed time:[NSDate date] type:MessageTypeSent context:@"" Done:NO];
    [self.messages addObject:userMsg];
    NSIndexPath *userPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    self.textfield.text = @"";
    self.sendButton.enabled = NO;
    self.sendButton.backgroundColor = RGB(203, 203, 203);
    [self.tableView beginUpdates];
    [self.tableView insertRowsAtIndexPaths:@[userPath] withRowAnimation:UITableViewRowAnimationAutomatic];
    [self.tableView endUpdates];
    [self scrollToBottom];
    [ChatStorage saveMessages:self.messages forChatId:self.chatId];

    // 追加 AI 占位消息
    MessageModel *aiPlaceholder = [[MessageModel alloc] initWithText:@"" time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO];
    [self.messages addObject:aiPlaceholder];
    self.hasSpokenCurrentAI = NO;
    self.lastSpokenIndex = 0;
    self.speakingMessageRow = self.messages.count - 1;
    NSIndexPath *aiPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    [self.tableView beginUpdates];
    [self.tableView insertRowsAtIndexPaths:@[aiPath] withRowAnimation:UITableViewRowAnimationAutomatic];
    [self.tableView endUpdates];
    [self scrollToBottom];
    [ChatStorage saveMessages:self.messages forChatId:self.chatId];

    // 启动输入中动画
    [self stopTypingIndicator]; // 先清理
    self.typingStep = 0;
    [self startTypingIndicator];

    // AI 服务回调
    AiServerManager *mgr = [AiServerManager sharedManager];
    __weak typeof(self) weakSelf = self;
    mgr.onPartialUpdate = ^(NSString *partialText) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        if (partialText.length > 0) {
            [self stopTypingIndicator];
            if (self.voiceEnabled) {
                [self enqueueClosedSentencesForLatestAI];
            }
        }
        NSIndexPath *last = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        [self.tableView reloadRowsAtIndexPaths:@[last] withRowAnimation:UITableViewRowAnimationNone];
        [self scrollToBottom];
    };
    mgr.onDoneUpdate = ^(NSArray *context, NSString *finalText) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        [self stopTypingIndicator];
        if (self.voiceEnabled) {
            self.speakingMessageRow = self.messages.count - 1;
            if (self.speechDebounceTimer) {
                [self.speechDebounceTimer invalidate];
                self.speechDebounceTimer = nil;
            }
            [self enqueueClosedSentencesForLatestAI];
            if (finalText.length > self.lastSpokenIndex) {
                NSString *tail = [finalText substringFromIndex:self.lastSpokenIndex];
                NSString *lang = [self isChineseText:tail] ? @"zh-CN" : @"en-US";
                [self enqueueSpeakText:tail language:lang];
                self.lastSpokenIndex = finalText.length;
            }
        }
        NSIndexPath *last = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        [self.tableView reloadRowsAtIndexPaths:@[last] withRowAnimation:UITableViewRowAnimationNone];
        [self scrollToBottom];
        self.sendButton.enabled = NO;
        self.sendButton.backgroundColor = RGB(203, 203, 203);
        [ChatStorage saveMessages:self.messages forChatId:self.chatId];
    };

    // 语言提示：提示语统一为英文（保持语义：中文问题→用中文回答）
    NSString *payloadText = trimmed;
    if ([self isChineseText:trimmed]) {
        payloadText = [NSString stringWithFormat:@"%@\n(Please respond in Chinese.)", trimmed];
    } else {
        payloadText = [NSString stringWithFormat:@"%@\n(Please respond in English.)", trimmed];
    }
    [[AiServerManager sharedManager] sendPOSTRequestAndHandleStreamResponse:payloadText belongMessages:self.messages];
}

#pragma mark - Typing Indicator

- (void)startTypingIndicator {
    if (self.typingTimer) {
        [self.typingTimer invalidate];
        self.typingTimer = nil;
    }
    __weak typeof(self) weakSelf = self;
    self.typingTimer = [NSTimer scheduledTimerWithTimeInterval:0.6 repeats:YES block:^(NSTimer * _Nonnull timer) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        [self updateTypingIndicator];
    }];
}

- (void)stopTypingIndicator {
    if (self.typingTimer) {
        [self.typingTimer invalidate];
        self.typingTimer = nil;
    }
}

- (void)updateTypingIndicator {
    if (self.messages.count == 0) return;
    MessageModel *last = [self.messages lastObject];
    if (last.type != MessageTypeReceived || last.done) {
        [self stopTypingIndicator];
        return;
    }
    self.typingStep = (self.typingStep + 1) % 3;
    switch (self.typingStep) {
        case 0: last.text = @"."; break;
        case 1: last.text = @".."; break;
        default: last.text = @"..."; break;
    }
    NSIndexPath *lastPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    [self.tableView reloadRowsAtIndexPaths:@[lastPath] withRowAnimation:UITableViewRowAnimationNone];
    [self scrollToBottom];
}

#pragma mark - Keyboard Handling

- (void)keyboardWillChange:(NSNotification *)notification {
    NSDictionary *info = notification.userInfo;
    NSTimeInterval duration = [info[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationCurve curve = [info[UIKeyboardAnimationCurveUserInfoKey] integerValue];
    CGRect endFrame = [info[UIKeyboardFrameEndUserInfoKey] CGRectValue];
    CGRect keyboardFrameInView = [self.view convertRect:endFrame fromView:nil];
    CGFloat keyboardHeight = MAX(0.0, CGRectGetMaxY(self.view.bounds) - CGRectGetMinY(keyboardFrameInView));

    CGFloat desiredOverlap = ZOOM(22);
    CGFloat offsetDistance = MAX(0.0, keyboardHeight - desiredOverlap);
    [self.inputViewBottomConstraint setOffset:-offsetDistance];
    [UIView animateWithDuration:duration delay:0 options:(curve << 16) animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
    [self scrollToBottom];
}

- (void)keyboardWillHide:(NSNotification *)notification {
    NSDictionary *info = notification.userInfo;
    NSTimeInterval duration = [info[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationCurve curve = [info[UIKeyboardAnimationCurveUserInfoKey] integerValue];
    [self.inputViewBottomConstraint setOffset:0];
    [UIView animateWithDuration:duration delay:0 options:(curve << 16) animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
}

- (void)handleTapOutside {
    [self.view endEditing:YES];
