#pragma mark - Language

- (BOOL)isChineseText:(NSString *)text {
    if (text.length == 0) return NO;
    NSRange r = [text rangeOfString:@"[\u4e00-\u9fff]" options:NSRegularExpressionSearch];
    return r.location != NSNotFound;
}

#pragma mark - Voice Synthesis

- (void)updateVoiceBarItemAppearance {
