            NSString *absPath = [ChatStorage avatarPathForChatId:self.chatId];
            if ([[NSFileManager defaultManager] fileExistsAtPath:absPath]) {
                avatarImage = [UIImage imageWithContentsOfFile:absPath];
            }
        }
        if (!avatarImage) {
            avatarImage = [UIImage imageNamed:@"A_defaultAvatar"];
