        if ([icon isEqualToString:@"A_emo"] || [title isEqualToString:@"Emotion"] || [title isEqualToString:@"感情"]) {
            if (![item.title isEqualToString:@"感情"]) { item.title = @"感情"; changed = YES; }
            if (![item.subtitle isEqualToString:@"你可以问我一些关于情感方面的问题。"]) { item.subtitle = @"你可以问我一些关于情感方面的问题。"; changed = YES; }
            if (![item.time isEqualToString:@"20:30"]) { item.time = @"20:30"; changed = YES; }
            [self migrateSampleMessagesIfNeededForChatItem:item sampleKey:@"emotion"];
        } else if ([icon isEqualToString:@"A_out"] || [title isEqualToString:@"Outdoor sports"] || [title isEqualToString:@"学习"]) {
            if (![item.title isEqualToString:@"学习"]) { item.title = @"学习"; changed = YES; }
            if (![item.subtitle isEqualToString:@"精通古代诗歌"]) { item.subtitle = @"精通古代诗歌"; changed = YES; }
            if (![item.time isEqualToString:@"19:45"]) { item.time = @"19:45"; changed = YES; }
            [self migrateSampleMessagesIfNeededForChatItem:item sampleKey:@"learn"];
        } else if ([icon isEqualToString:@"A_music"] || [title isEqualToString:@"Music"] || [title isEqualToString:@"文案撰写"]) {
