+ (void)migrateSampleMessagesIfNeededForChatItem:(ChatItemModel *)item sampleKey:(NSString *)sampleKey {
    if (!item || item.chatId.length == 0 || sampleKey.length == 0) return;

    NSArray<NSString *> *preset = [self presetTextsForSampleKey:sampleKey];
    if (preset.count == 0) return;

    NSArray<MessageModel *> *current = [self loadMessagesForChatId:item.chatId];
    if (current.count == 0 || current.count > 4) return;

    NSMutableString *allText = [NSMutableString string];
    for (MessageModel *msg in current) {
        if (msg.type != MessageTypeReceived) return;
        if (msg.text.length > 0) {
            [allText appendString:msg.text];
        }
    }
    if (allText.length == 0) return;

    NSRange englishRange = [allText rangeOfString:@"[A-Za-z]" options:NSRegularExpressionSearch];
    if (englishRange.location == NSNotFound) return;

    NSMutableArray<MessageModel *> *migrated = [NSMutableArray arrayWithCapacity:preset.count];
    for (NSString *t in preset) {
        [migrated addObject:[[MessageModel alloc] initWithText:t time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO]];
    }
    [self saveMessages:migrated forChatId:item.chatId];
}

