    NSMutableArray<MessageModel *> *list = [NSMutableArray array];
    NSString *path = [self messagesFilePathForChatId:chatId];
    NSData *data = [NSData dataWithContentsOfFile:path];
    if (data) {
        NSError *err = nil;
        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&err];
        if (!err && [obj isKindOfClass:[NSArray class]]) {
            for (NSDictionary *d in (NSArray *)obj) {
                if (![d isKindOfClass:[NSDictionary class]]) continue;
                NSString *text = d[@"text"] ?: @"";
                NSNumber *ts = d[@"time"] ?: @(NSDate.date.timeIntervalSince1970);
                NSDate *time = [NSDate dateWithTimeIntervalSince1970:ts.doubleValue];
                MessageType type = (MessageType)[d[@"type"] integerValue];
                NSString *context = d[@"context"] ?: @"";
                BOOL done = [d[@"done"] boolValue];
                MessageModel *m = [[MessageModel alloc] initWithText:text time:time type:type context:context Done:done];
                NSNumber *mn = d[@"messagenum"]; if (mn) { m.messagenum = mn.integerValue; }
                [list addObject:m];
            }
        }
    }
    return list;
}

+ (void)saveMessages:(NSArray<MessageModel *> *)messages forChatId:(NSString *)chatId {
    NSMutableArray *arr = [NSMutableArray arrayWithCapacity:messages.count];
    for (MessageModel *m in messages) {
        NSDictionary *d = @{ @"text": m.text ?: @"",
                             @"time": @([m.time timeIntervalSince1970]),
                             @"type": @(m.type),
                             @"context": m.context ?: @"",
                             @"done": @(m.done),
                             @"messagenum": @(m.messagenum) };
        [arr addObject:d];
    }
    NSError *err = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:arr options:0 error:&err];
    if (!err && data) {
        [data writeToFile:[self messagesFilePathForChatId:chatId] atomically:YES];
    }
}

+ (void)clearMessagesForChatId:(NSString *)chatId {
    NSString *path = [self messagesFilePathForChatId:chatId];
    [[NSFileManager defaultManager] removeItemAtPath:path error:nil];
}

+ (void)ensureDefaultChatsExist {
    NSString *path = [self chatListFilePath];
    if ([[NSFileManager defaultManager] fileExistsAtPath:path]) {
        return;
    }

    // 创建示例聊天列表项（仅前三个固定示例，其他为用户自建）
    ChatItemModel *c1 = [[ChatItemModel alloc] init];
    c1.chatId = [[NSUUID UUID] UUIDString];
    c1.title = @"感情";
    c1.subtitle = @"你可以问我一些关于情感方面的问题。";
    c1.time = @"20:30";
    c1.icon = @"A_emo";

    ChatItemModel *c2 = [[ChatItemModel alloc] init];
    c2.chatId = [[NSUUID UUID] UUIDString];
    c2.title = @"学习";
    c2.subtitle = @"精通古代诗歌";
    c2.time = @"19:45";
    c2.icon = @"A_out";

    ChatItemModel *c3 = [[ChatItemModel alloc] init];
    c3.chatId = [[NSUUID UUID] UUIDString];
    c3.title = @"文案撰写";
    c3.subtitle = @"热销文案";
    c3.time = @"19:35";
    c3.icon = @"A_music";

    NSArray<ChatItemModel *> *defaults = @[c1, c2, c3];
    [self saveChatList:defaults];

    void (^savePreset)(ChatItemModel *, NSArray<NSString *> *) = ^(ChatItemModel *item, NSArray<NSString *> *texts) {
        NSMutableArray<MessageModel *> *msgs = [NSMutableArray array];
        for (NSString *t in texts) {
            MessageModel *m = [[MessageModel alloc] initWithText:t time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO];
            [msgs addObject:m];
        }
        [self saveMessages:msgs forChatId:item.chatId];
    };

    savePreset(c1, [self presetTextsForSampleKey:@"emotion"]);
    savePreset(c2, [self presetTextsForSampleKey:@"learn"]);
    savePreset(c3, [self presetTextsForSampleKey:@"copy"]);
}

// 根据聊天标题返回默认预设消息；若非示例项则返回主界面问候语
+ (NSArray<MessageModel *> *)defaultPresetMessagesForChatId:(NSString *)chatId {
    NSArray<ChatItemModel *> *list = [self loadChatList];
    ChatItemModel *target = nil;
    for (ChatItemModel *item in list) {
        if ([item.chatId isEqualToString:chatId]) { target = item; break; }
    }

    NSString *sampleKey = nil;
    if ([target.title isEqualToString:@"感情"]) {
        sampleKey = @"emotion";
    } else if ([target.title isEqualToString:@"学习"]) {
        sampleKey = @"learn";
    } else if ([target.title isEqualToString:@"文案撰写"]) {
        sampleKey = @"copy";
    }

    NSMutableArray<MessageModel *> *msgs = [NSMutableArray array];
    NSArray<NSString *> *texts = [self presetTextsForSampleKey:sampleKey ?: @""];
    if (texts.count > 0) {
        for (NSString *t in texts) {
            [msgs addObject:[[MessageModel alloc] initWithText:t time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO]];
        }
        return msgs;
    }

    [msgs addObject:[[MessageModel alloc] initWithText:@"你今天在看什么？" time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO]];
    return msgs;
}

// 清空后恢复默认预设消息并保存
+ (void)resetMessagesToPresetForChatId:(NSString *)chatId {
    [self clearMessagesForChatId:chatId];
    NSArray<MessageModel *> *preset = [self defaultPresetMessagesForChatId:chatId];
    [self saveMessages:preset forChatId:chatId];
}

