/// 能让视图显示类似被点击时的动画效果
/// @param level 缩放等级
- (void)showClickedAnimationWithLevel:(NSUInteger)level {
    CAKeyframeAnimation *anim = [[CAKeyframeAnimation alloc] init];
    anim.keyPath = @"transform";
    anim.duration = 0.2;
    anim.removedOnCompletion = YES;
    anim.fillMode = kCAFillModeForwards;

    CGFloat factor = 1.0 + level * 0.02;

    // 创建关键帧数组
    NSMutableArray *arrayKeyFrames = [NSMutableArray arrayWithCapacity:3];
    [arrayKeyFrames addObject:[NSValue valueWithCATransform3D:CATransform3DMakeScale(1.0, 1.0, 1.0)]];
    [arrayKeyFrames addObject:[NSValue valueWithCATransform3D:CATransform3DMakeScale(factor, factor, 1.0)]];
    [arrayKeyFrames addObject:[NSValue valueWithCATransform3D:CATransform3DMakeScale(1.0, 1.0, 1.0)]];
    anim.values = arrayKeyFrames;

    // 把动画加到图层
    [self.layer addAnimation:anim forKey:nil];
}

