#import "MessageModel.h"

@implementation MessageModel

- (instancetype)initWithText:(NSString *)text time:(NSDate *)time type:(MessageType)type context:(NSString*)context Done:(BOOL)done {
    self = [super init];
    if (self) {
        _text = [text copy] ?: @"";
        _time = time ?: [NSDate date];
        _type = type;
        _context = [context copy] ?: @"";
        _done = done;
        _messagenum = 0;
    }
    return self;
}

// MARK: - Persistence

static NSMutableArray<MessageModel *> *_messagesStore = nil;

+ (NSString *)filePath {
    NSArray *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
    NSString *doc = paths.firstObject ?: NSTemporaryDirectory();
    return [doc stringByAppendingPathComponent:@"messages.json"];
}

// 将模型转为字典
+ (NSDictionary *)dictionaryFromMessage:(MessageModel *)msg {
    return @{ @"text": msg.text ?: @"",
              @"time": @([msg.time timeIntervalSince1970]),
              @"type": @(msg.type),
              @"context": msg.context ?: @"",
              @"done": @(msg.done),
              @"messagenum": @(msg.messagenum) };
}

// 将字典转为模型
+ (MessageModel *)messageFromDictionary:(NSDictionary *)dict {
    NSString *text = dict[@"text"] ?: @"";
    NSNumber *ts = dict[@"time"] ?: @(NSDate.date.timeIntervalSince1970);
    NSDate *time = [NSDate dateWithTimeIntervalSince1970:ts.doubleValue];
    MessageType type = (MessageType)[dict[@"type"] integerValue];
    NSString *context = dict[@"context"] ?: @"";
    BOOL done = [dict[@"done"] boolValue];
    MessageModel *m = [[MessageModel alloc] initWithText:text time:time type:type context:context Done:done];
    NSNumber *mn = dict[@"messagenum"];
    if (mn) { m.messagenum = mn.integerValue; }
    return m;
}

// 保证问候语固定在第一、第二条
+ (void)ensureGreetingsAtTop:(NSMutableArray<MessageModel *> *)array {
    NSString *assistant = [self assistantDisplayName];
    NSString *greet1Text = [NSString stringWithFormat:@"你好! 我是 %@.", assistant];
    NSString *greet2Text = [NSString stringWithFormat:@"你好, %@!", assistant];

    // 移除已有的重复问候语
    NSIndexSet *toRemove = [array indexesOfObjectsPassingTest:^BOOL(MessageModel * _Nonnull obj, NSUInteger idx, BOOL * _Nonnull stop) {
        BOOL isGreet1 = ([obj.text isEqualToString:greet1Text] && obj.type == MessageTypeReceived);
        BOOL isGreet2 = ([obj.text isEqualToString:greet2Text] && obj.type == MessageTypeSent);
        return isGreet1 || isGreet2;
    }];
    if (toRemove.count > 0) {
        [array removeObjectsAtIndexes:toRemove];
    }

    // 构建两条固定问候语并插入到顶部
    MessageModel *m1 = [[MessageModel alloc] initWithText:greet1Text time:[NSDate date] type:MessageTypeReceived context:@"" Done:NO];
    MessageModel *m2 = [[MessageModel alloc] initWithText:greet2Text time:[NSDate date] type:MessageTypeSent context:@"" Done:NO];

    [array insertObject:m2 atIndex:0];
    [array insertObject:m1 atIndex:0];
}

+ (NSMutableArray<MessageModel *> *)messages {
    if (_messagesStore) {
        return _messagesStore;
    }
    _messagesStore = [NSMutableArray array];
    NSString *path = [self filePath];
    NSData *data = [NSData dataWithContentsOfFile:path];
    if (data) {
        NSError *error = nil;
        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
        if (!error && [obj isKindOfClass:[NSArray class]]) {
            for (NSDictionary *d in (NSArray *)obj) {
                if ([d isKindOfClass:[NSDictionary class]]) {
                    MessageModel *m = [self messageFromDictionary:d];
                    [_messagesStore addObject:m];
                }
            }
        }
    }
    // 确保问候语在最前面
    [self ensureGreetingsAtTop:_messagesStore];
    return _messagesStore;
}

+ (void)saveMessages {
    if (!_messagesStore) { return; }
    NSMutableArray *arr = [NSMutableArray arrayWithCapacity:_messagesStore.count];
    for (MessageModel *m in _messagesStore) {
        [arr addObject:[self dictionaryFromMessage:m]];
    }
    NSError *error = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:arr options:0 error:&error];
    if (!error && data) {
        [data writeToFile:[self filePath] atomically:YES];
    }
}

+ (void)deleteMessagesFile {
    NSString *path = [self filePath];
    [[NSFileManager defaultManager] removeItemAtPath:path error:nil];
    _messagesStore = nil;
}

+ (NSInteger)messagenum {
    return [[NSUserDefaults standardUserDefaults] integerForKey:@"MessageModel.messagenum"];
}

+ (void)saveMessageNum:(NSInteger)messagenum {
    [[NSUserDefaults standardUserDefaults] setInteger:messagenum forKey:@"MessageModel.messagenum"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

// 获取用户自定义的助理名称，未设置则默认“小七”
+ (NSString *)assistantDisplayName {
    NSString *name = [[NSUserDefaults standardUserDefaults] stringForKey:@"assistantName"];
    if (name == nil || name.length == 0) {
        name = @"Xiaoqi";
    }
    return name;
}


